  1069	int flb_parser_tzone_offset(const char *str, int len, int *tmdiff)
  1070	{
  1071	    int neg;
  1072	    long hour;
  1073	    long min;
  1074	    const char *end;
  1075	    const char *p = str;
  1076	
  1077	    /* Check timezones */
  1078	    if (*p == 'Z') {
  1079	        /* This is UTC, no changes required */
  1080	        *tmdiff = 0;
  1081	        return 0;
  1082	    }
  1083	
  1084	    /* Unexpected timezone string */
  1085	    if (*p != '+' && *p != '-') {
  1086	        *tmdiff = 0;
  1087	        return -1;
  1088	    }
  1089	
  1090	    /* Ensure there is enough data */
  1091	    if (len < 4) {
  1092	        *tmdiff = 0;
  1093	        return -1;
  1094	    }
  1095	
  1096	    /* Negative value ? */
  1097	    neg = (*p++ == '-');
  1098	
  1099	    /* Locate end */
  1100	    end = str + len;
  1101	
  1102	    /* Gather hours and minutes */
  1103	    hour = ((p[0] - '0') * 10) + (p[1] - '0');
  1104	    if (end - p == 5 && p[2] == ':') {
  1105	        /* Ensure there is enough data */
  1106	        if (len < 5) {
  1107	            *tmdiff = 0;
  1108	            return -1;
  1109	        }
  1110	        min = ((p[3] - '0') * 10) + (p[4] - '0');
  1111	    }
  1112	    else {
  1113	        min = ((p[2] - '0') * 10) + (p[3] - '0');
  1114	    }
  1115	
  1116	    if (hour < 0 || hour > 59 || min < 0 || min > 59) {
  1117	        return -1;
  1118	    }
  1119	
  1120	    *tmdiff = ((hour * 3600) + (min * 60));
  1121	    if (neg) {
  1122	        *tmdiff = -*tmdiff;
  1123	    }
  1124	
  1125	    return 0;
  1126	}
