/* Test reproduction for midnight timezone bug */
#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <time.h>

/* Simulate the core logic */
int main() {
    /*
     * We simulate what happens when:
     * - System TZ: Europe/Stockholm (UTC+2, CEST)
     * - Current time: 2025-03-30 00:01:00 CEST
     * - Log time: "00:01:00" (just time, no date)
     * - Time_System_Timezone: on
     * - Time_Format: %H:%M:%S
     */

    /* Simulate two scenarios: gmtime_r (old/buggy) vs localtime_r (fixed) */

    /* Set time to 2025-03-30 00:01:00 CEST = 2025-03-29 22:01:00 UTC */
    struct tm local_tm = {0};
    local_tm.tm_year = 2025 - 1900;
    local_tm.tm_mon = 2;   /* March (0-indexed) */
    local_tm.tm_mday = 30;
    local_tm.tm_hour = 0;
    local_tm.tm_min = 1;
    local_tm.tm_sec = 0;
    local_tm.tm_isdst = 1; /* DST */

    /* Simulate TZ=Europe/Stockholm */
    setenv("TZ", "Europe/Stockholm", 1);
    tzset();

    time_t now = mktime(&local_tm);
    printf("Current time: %s", ctime(&now));
    printf("Unix timestamp: %ld\n\n", (long)now);

    /* OLD behavior: gmtime_r */
    struct tm tmy_gmt;
    gmtime_r(&now, &tmy_gmt);
    printf("=== OLD (gmtime_r) ===\n");
    printf("Date from gmtime_r: %04d-%02d-%02d (UTC)\n",
           tmy_gmt.tm_year + 1900, tmy_gmt.tm_mon + 1, tmy_gmt.tm_mday);

    /* This would be used as the date for "00:01:00" */
    struct tm parsed_gmt = {0};
    parsed_gmt.tm_year = tmy_gmt.tm_year;
    parsed_gmt.tm_mon = tmy_gmt.tm_mon;
    parsed_gmt.tm_mday = tmy_gmt.tm_mday;
    parsed_gmt.tm_hour = 0;
    parsed_gmt.tm_min = 1;
    parsed_gmt.tm_sec = 0;
    parsed_gmt.tm_isdst = -1; /* auto-detect */

    time_t result_gmt = mktime(&parsed_gmt);
    printf("Combined date+time: %04d-%02d-%02d %02d:%02d:%02d\n",
           parsed_gmt.tm_year + 1900, parsed_gmt.tm_mon + 1, parsed_gmt.tm_mday,
           parsed_gmt.tm_hour, parsed_gmt.tm_min, parsed_gmt.tm_sec);
    printf("Result timestamp: %ld", (long)result_gmt);
    printf(" (%s", ctime(&result_gmt));
    printf("Date is %s than now\n\n", result_gmt < now ? "EARLIER - BUG!" : "later/same - OK");

    /* NEW behavior: localtime_r (fix) */
    struct tm tmy_local;
    localtime_r(&now, &tmy_local);
    printf("=== NEW (localtime_r) ===\n");
    printf("Date from localtime_r: %04d-%02d-%02d (local)\n",
           tmy_local.tm_year + 1900, tmy_local.tm_mon + 1, tmy_local.tm_mday);

    struct tm parsed_local = {0};
    parsed_local.tm_year = tmy_local.tm_year;
    parsed_local.tm_mon = tmy_local.tm_mon;
    parsed_local.tm_mday = tmy_local.tm_mday;
    parsed_local.tm_hour = 0;
    parsed_local.tm_min = 1;
    parsed_local.tm_sec = 0;
    parsed_local.tm_isdst = -1;

    time_t result_local = mktime(&parsed_local);
    printf("Combined date+time: %04d-%02d-%02d %02d:%02d:%02d\n",
           parsed_local.tm_year + 1900, parsed_local.tm_mon + 1, parsed_local.tm_mday,
           parsed_local.tm_hour, parsed_local.tm_min, parsed_local.tm_sec);
    printf("Result timestamp: %ld", (long)result_local);
    printf(" (%s", ctime(&result_local));
    printf("Date is %s than now\n\n", result_local < now ? "EARLIER - BUG!" : "later/same - OK");

    /* Also test with UTC timezone to make sure no regression */
    printf("=== UTC timezone test (no System_Timezone) ===\n");
    setenv("TZ", "UTC", 1);
    tzset();

    /* With UTC, gmtime_r and localtime_r give the same date */
    struct tm tmy_utc_gmt, tmy_utc_local;
    gmtime_r(&now, &tmy_utc_gmt);
    localtime_r(&now, &tmy_utc_local);
    printf("gmtime_r date:    %04d-%02d-%02d\n",
           tmy_utc_gmt.tm_year + 1900, tmy_utc_gmt.tm_mon + 1, tmy_utc_gmt.tm_mday);
    printf("localtime_r date: %04d-%02d-%02d\n",
           tmy_utc_local.tm_year + 1900, tmy_utc_local.tm_mon + 1, tmy_utc_local.tm_mday);
    printf("Dates match: %s\n",
           tmy_utc_gmt.tm_mday == tmy_utc_local.tm_mday ? "YES - no regression" : "NO - would be a regression");

    return 0;
}
EOF
